var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`ARIUS_ZODIAC_RACING_NULL`,text:{KOREA:`늘 이런 넓은 곳에 혼자만 계시다니.`,JPN:`こんな広い所に、いつも一人でいるなんて……`,ENG:`You're always in this big office all by yourself.`,TWN:`您竟然一直獨自待在這麼大的房間。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARIUS_ZODIAC_RACING_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`ARIUS_ZODIAC_RACING_NULL`,text:{KOREA:`혹시 사장님께서도 몸이 약해서 밖으로 나오는 게 불편하신 건가요?`,JPN:`もしかして、社長も体が弱くて、あまりお外に出られないんですか？`,ENG:`Are you so frail that you can't go out often, too?`,TWN:`難道老闆也是因為身體不好，不方便出門嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARIUS_ZODIAC_RACING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`ARIUS_ZODIAC_RACING_NULL`,text:{KOREA:`아, 건강하시다니 안심이에요. 그럼 오늘 저랑 같이 재미있는 곳에......`,JPN:`あ、元気ならよかったです。じゃあ、今日は私と一緒に楽しいところへ……`,ENG:`Ah, I'm glad you're not. Then, maybe we can go out and have fun together today.`,TWN:`啊！聽到您身體很健康我就放心了。那麼今天，就和我一起去個有趣的地方……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARIUS_ZODIAC_RACING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`ARIUS_ZODIAC_RACING_NULL`,text:{KOREA:`아! 그러고 보니 제게 제안할 게 있다고 부르셨죠.`,JPN:`あっ！そういえば、私に提案があるって話でしたね。`,ENG:`Oh, I'm sorry. You wanted to talk to me about something.`,TWN:`啊！話說回來，聽說您是有事才叫我的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARIUS_ZODIAC_RACING_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`ARIUS_ZODIAC_RACING_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARIUS_ZODIAC_RACING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`ARIUS_ZODIAC_RACING_NULL`,text:{KOREA:`와아, 종신계약이라니! 이런 건 처음 받아봐요. 신기해라.`,JPN:`わぁ、終身契約だなんて！こんなの初めてです。何だか不思議……`,ENG:`Whoa, a lifetime contract?! I've never had such an offer before! How marvelous!`,TWN:`哇，終身契約！我還是第一次收到這種東西，好神奇啊。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARIUS_ZODIAC_RACING_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`ARIUS_ZODIAC_RACING_NULL`,text:{KOREA:`그렇다는 건 저를 믿어주시는 거죠? 제 마음이 전해진 것 같아 기뻐요.`,JPN:`これって、私を信頼してくれてるってことですよね？私の気持ちが伝わった気がして、嬉しいです。`,ENG:`This means you trust me, right? I'm so happy you do.`,TWN:`這代表老闆很信任我對吧？我的心意能傳達給老闆，我好開心喔。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARIUS_ZODIAC_RACING_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};